if (! function_exists('text_anagram_finder')) {
    function text_anagram_finder($word, $wordlist, $mode = null, $case_sensitive = null, $max_results = null)
    {
        $word = trim($word);
        if (empty($word) || !is_array($wordlist) || empty($wordlist)) {
            return json_encode(['error' => 'Word and non-empty wordlist are required', 'anagrams' => []]);
        }
        $caseSensitive = isset($caseSensitive) ? (bool)$caseSensitive : false;
        $mode = isset($mode) ? $mode : 'exact';
        $max = isset($max_results) && $max_results > 0 ? (int)$max_results : 50;

        // Normalize the target word
        $target = $caseSensitive ? $word : mb_strtolower($word);
        $targetSorted = str_split($target);
        sort($targetSorted);
        $targetSig = implode('', $targetSorted);

        // Build letter frequency map for near mode
        $targetFreq = [];
        foreach (str_split($target) as $ch) {
            $targetFreq[$ch] = ($targetFreq[$ch] ?? 0) + 1;
        }

        $exact = [];
        $near = [];

        foreach ($wordlist as $candidate) {
            $cand = trim((string)$candidate);
            if ($cand === '' || $cand === $word) continue;
            $candNorm = $caseSensitive ? $cand : mb_strtolower($cand);

            $candSorted = str_split($candNorm);
            sort($candSorted);
            $candSig = implode('', $candSorted);

            if ($candSig === $targetSig) {
                $exact[] = $cand;
            } elseif ($mode === 'near') {
                // Check near-anagram: off by exactly 1 character (insert, delete, or substitute)
                $lenDiff = abs(strlen($target) - strlen($candNorm));
                if ($lenDiff > 1) continue;

                // Build frequency difference
                $candFreq = [];
                foreach (str_split($candNorm) as $ch) {
                    $candFreq[$ch] = ($candFreq[$ch] ?? 0) + 1;
                }

                $diffCount = 0;
                $allChars = array_unique(array_merge(array_keys($targetFreq), array_keys($candFreq)));
                foreach ($allChars as $ch) {
                    $tCount = $targetFreq[$ch] ?? 0;
                    $cCount = $candFreq[$ch] ?? 0;
                    $diffCount += abs($tCount - $cCount);
                }

                // diffCount of 2 means one substitution or one add+delete (off by 1 char)
                if ($diffCount <= 2 && $lenDiff <= 1) {
                    $near[] = $cand;
                }
            }
        }

        $results = $exact;
        if ($mode === 'near') {
            $results = array_merge($results, $near);
        }
        $results = array_slice($results, 0, $max);

        return json_encode([
            'word' => $word,
            'mode' => $mode,
            'candidates_checked' => count($wordlist),
            'exact_count' => count($exact),
            'near_count' => $mode === 'near' ? count($near) : 0,
            'anagrams' => $results,
        ]);
    }
